#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
P20 — Restore CP (conformal) gate in gate_meta.py (so CPREG works again)

This patch overwrites src/natbin/gate_meta.py with a fixed version that:
- keeps base + calibrated proba + iso(conf) + meta + meta_iso (P15)
- reintroduces conformal CP gate so gate_mode='cp' and CP_ALPHA actually matter
"""
from __future__ import annotations

import base64
import py_compile
import shutil
from datetime import datetime
from pathlib import Path


def stamp() -> str:
    return datetime.now().strftime("%Y%m%d_%H%M%S")


def find_repo_root() -> Path:
    cwd = Path.cwd().resolve()
    if (cwd / "src" / "natbin").exists():
        return cwd
    here = Path(__file__).resolve()
    for p in [here.parent] + list(here.parents):
        if (p / "src" / "natbin").exists():
            return p
    raise SystemExit("P20: não encontrei src/natbin. Rode a partir do root do repo.")


GATE_META_B64 = """"""


def main() -> None:
    root = find_repo_root()
    path = root / "src" / "natbin" / "gate_meta.py"
    if not path.exists():
        raise SystemExit(f"P20: não achei {path}")

    backup = path.with_suffix(path.suffix + f".bak_{stamp()}")
    shutil.copy2(path, backup)

    content = base64.b64decode(GATE_META_B64.encode("ascii")).decode("utf-8")
    path.write_text(content, encoding="utf-8", newline="\n")

    try:
        py_compile.compile(str(path), doraise=True)
    except Exception as e:
        print("[P20] ERROR: py_compile falhou:", e)
        print(f"[P20] Backup salvo em: {backup}")
        raise SystemExit(2)

    print(f"[P20] OK {path}")
    print(f"[P20] backup: {backup}")
    print("[P20] Teste rápido:")
    print("  - backtest gate_mode=cp e altere CP_ALPHA (0.01 vs 0.20) -> nº trades deve mudar.")


if __name__ == "__main__":
    main()
